import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return None  # All nodes are visited; the algorithm ends or truck waits

    # Penalize based on distance and next truck destination density
    values_to_unvisited = np.full(len(unvisited_nodes), np.inf)

    # Calculate a penalty for each unvisited node based on the inverse of its distance to depot
    depot_distances = distance_matrix[unvisited_nodes, depot_node]
    inv_depot_distances = 1 / (depot_distances + 1)  # Adding 1 to avoid division by zero

    for i, node in enumerate(unvisited_nodes):
        if node not in truck_nodes:
            values_to_unvisited[i] = distance_matrix[current_node, node] - inv_depot_distances[i]

    # Select the unvisited node with the minimum penalized value (if any valid values exist)
    if np.min(values_to_unvisited) < np.inf:
        next_node_index = np.argmin(values_to_unvisited)
        next_node = unvisited_nodes[next_node_index]
    else:
        # All nodes might be targeted by other trucks, wait for a better opportunity
        return None

    return next_node

import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return None

    scores = np.full(len(unvisited_nodes), -np.inf)

    current_to_unvisited = distance_matrix[current_node, unvisited_nodes]
    unvisited_to_depot = distance_matrix[unvisited_nodes, depot_node]

    for i, node in enumerate(unvisited_nodes):
        if node not in truck_nodes:
            proximity_score = -np.sqrt(current_to_unvisited[i])  # use square root to diminish effect of long distances
            depot_direction_score = -unvisited_to_depot[i]
            scores[i] = depot_direction_score + proximity_score  # shifted focus towards depot proximity

    if np.max(scores) > -np.inf:
        best_index = np.argmax(scores)
        next_node = unvisited_nodes[best_index]
    else:
        return None

    return next_node
